let itemInfo: [string, number] = ["Shirt", 50];
// itemInfo = [50, "Shirt"]; // Xəta: tip sırası yanlış

// 2. Tuple içində müxtəlif tiplər
let productData: [string, number, boolean] = ["Jacket", 100, true];

// 3. Tuple ilə funksiya
function getItemDetails(): [string, number] {
  return ["Hat", 25];
}
const details = getItemDetails();

// 4. Tuple və interface ilə işləmə
interface Item {
  name: string;
  price: number;
}
let itemTuple: [Item, number] = [{ name: "Shirt", price: 50 }, 1];

// 5. Tuple array içində
let orderList: [string, number][] = [["Shirt", 50], ["Jacket", 100]];

