// Öz tuple types nümunəni yarat!
interface Item {
  name: string;
  price: number;
}

let items: [string, number][] = [
  ["Shirt", 50],
  ["Jacket", 100]
];

function printItem(tuple: [string, number]): void {
  console.log(`${tuple[0]}: $${tuple[1]}`);
}

items.forEach(item => printItem(item));

